const today = $('Get Today').item.json.records || [];
const week = $('Get Week').item.json.records || [];

let metrics = { new: today.length, hot: 0, warm: 0, cold: 0, contacted: 0, sources: {} };

for (const r of today) {
  const f = r.fields;
  if (f.Tier === 'Hot') metrics.hot++;
  else if (f.Tier === 'Warm') metrics.warm++;
  else metrics.cold++;
  if (['Contacted','Nurturing','Qualified'].includes(f.Status)) metrics.contacted++;
  const src = f.Source || 'Unknown';
  metrics.sources[src] = (metrics.sources[src] || 0) + 1;
}

let weekConverted = 0, totalScore = 0, scoreCount = 0;
for (const r of week) {
  if (r.fields.Status === 'Converted') weekConverted++;
  if (r.fields.LeadScore) { totalScore += r.fields.LeadScore; scoreCount++; }
}

let topSource = 'N/A', topCount = 0;
for (const [s, c] of Object.entries(metrics.sources)) {
  if (c > topCount) { topSource = s; topCount = c; }
}

// Generate insights without AI
let insights = [];
if (metrics.hot > 0) insights.push(`${metrics.hot} hot lead(s) need immediate attention!`);
if (metrics.rate >= 50) insights.push('Great contact rate today!');
else if (metrics.new > 0 && metrics.rate < 30) insights.push('Consider following up with more leads.');
if (topSource !== 'N/A') insights.push(`${topSource} is your top lead source.`);

return {
  json: {
    new_leads: metrics.new,
    hot: metrics.hot,
    warm: metrics.warm,
    cold: metrics.cold,
    contacted: metrics.contacted,
    rate: metrics.new > 0 ? Math.round((metrics.contacted / metrics.new) * 100) : 0,
    top_source: topSource,
    week_total: week.length,
    week_converted: weekConverted,
    avg_score: scoreCount > 0 ? (totalScore / scoreCount).toFixed(1) : 0,
    insights: insights.join(' ') || 'Keep up the good work!',
    date: new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
};
